SELECT COUNT(flight_id) AS total_flights
FROM flight_configurations
WHERE configuration = 'flight_config';

SELECT COUNT(DISTINCT route_id) 
FROM route_configurations 
WHERE config_id = 0;

SELECT COUNT(*) 
FROM permissions 
WHERE user_id = 1 AND permission_level = 'write';

SELECT created_by
FROM flight_plans
WHERE flight_id = 1 AND plan = 'flight_plan';

SELECT flight_id, tag_name
FROM flight_tags
WHERE tag_name != 'turbulence';

SELECT COUNT(flight_id)
FROM flight_tags
WHERE tag_name = 'turbulence' AND created_by = 0;

SELECT flight_id
FROM flight_tags
WHERE tag_name = 'weather';

SELECT flight_id 
FROM flights 
WHERE total_distance = (SELECT MAX(total_distance) FROM flights);
